import{c as a,Q as s,j as n,m as t}from"./chunks/framework.BPKcPtvA.js";const d=JSON.parse('{"title":"Checkout — for buyers","description":"What the buyer sees when they click a MuHaven pay link.","frontmatter":{"title":"Checkout — for buyers","description":"What the buyer sees when they click a MuHaven pay link."},"headers":[],"relativePath":"checkout/for-buyers.md","filePath":"checkout/for-buyers.md","lastUpdated":1778983454000}'),p={name:"checkout/for-buyers.md"};function o(i,e,l,r,c,h){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="hosted-checkout-—-for-buyers" tabindex="-1">Hosted Checkout — for buyers <a class="header-anchor" href="#hosted-checkout-—-for-buyers" aria-label="Permalink to &quot;Hosted Checkout — for buyers&quot;">​</a></h1><p>You received a pay link from someone you trust (an issuer, a partner, a friend), and it looks like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://muhaven.app/pay/c/01HMTV9X.../#k=AbCdEfGhIjKlMnOpQrStUvWxYz123456</span></span></code></pre></div><p>This is the <strong>MuHaven hosted checkout</strong> surface. Click the link in your browser. Returning buyers complete the flow quickly; first-time buyers create a passkey along the way.</p><h2 id="what-you-ll-see" tabindex="-1">What you&#39;ll see <a class="header-anchor" href="#what-you-ll-see" aria-label="Permalink to &quot;What you&#39;ll see&quot;">​</a></h2><p>The <code>/pay</code> page loads in your browser. Your browser sends the path (<code>/pay/c/01HMTV9X.../</code>) to MuHaven&#39;s servers, but <strong>not the fragment</strong> (<code>#k=...</code>) — fragments stay client-side by browser spec. The page renders:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  🪙 MuHaven                          │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  You&#39;re paying                                       │</span></span>
<span class="line"><span>│  ✓ RWA1 Treasury Issuer (Verified)                 │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Amount        500.00 mhUSDC                         │</span></span>
<span class="line"><span>│  For           500.00 RWA1 (~$501.50 USD)          │</span></span>
<span class="line"><span>│  Expires       in 23 hours 58 minutes                │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ──────────────────────────────────────────────      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  [Continue]                                          │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p>The cleartext amount and the issuer label come from <strong>decrypting the payload in your browser</strong> with the fragment key. The page&#39;s JavaScript:</p><ol><li>Reads <code>#k=...</code> from <code>window.location.hash</code>.</li><li>Fetches the ciphertext from <code>GET /api/v1/checkout/:sessionId/payload</code>.</li><li>Decrypts it locally with AES-256-GCM.</li><li>Renders.</li></ol><p>The server <strong>never</strong> sees the cleartext payload. See <a href="/checkout/fragment-key">URL fragment key</a>.</p><h2 id="step-1-first-time-buyers-—-create-a-passkey" tabindex="-1">Step 1 (first-time buyers) — Create a passkey <a class="header-anchor" href="#step-1-first-time-buyers-—-create-a-passkey" aria-label="Permalink to &quot;Step 1 (first-time buyers) — Create a passkey&quot;">​</a></h2><p>If you&#39;ve never used MuHaven before, the next click takes you through the passkey creation ceremony:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Welcome to MuHaven 🪙                               │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  To pay, you need a passkey. We&#39;ll create one for    │</span></span>
<span class="line"><span>│  you on this device — no seed phrase, no extension,  │</span></span>
<span class="line"><span>│  no email signup.                                    │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Your passkey is bound to muhaven.app and lives in   │</span></span>
<span class="line"><span>│  your device or password manager (iCloud Keychain,   │</span></span>
<span class="line"><span>│  1Password, Google Password Manager, hardware key).  │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  [Create passkey]                                    │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Tap <strong>Create passkey</strong>. Your OS shows the WebAuthn dialog (Touch ID / Windows Hello / hardware key). Approve.</p><p>Your <strong>MuHaven wallet</strong> (a ZeroDev-powered smart account) deploys in the background, paymaster-sponsored. You now have a MuHaven account — the same one you can use on the dashboard, on Telegram, or via MCP.</p><h2 id="step-1-returning-buyers-—-sign-in" tabindex="-1">Step 1 (returning buyers) — Sign in <a class="header-anchor" href="#step-1-returning-buyers-—-sign-in" aria-label="Permalink to &quot;Step 1 (returning buyers) — Sign in&quot;">​</a></h2><p>If you already have a MuHaven passkey on this device (or synced via your password manager), the page detects it and shows:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Continue with passkey]</span></span></code></pre></div><p>Tap it, pick your passkey from the OS dialog, and you&#39;re in.</p><h2 id="step-2-—-fund-if-needed" tabindex="-1">Step 2 — Fund (if needed) <a class="header-anchor" href="#step-2-—-fund-if-needed" aria-label="Permalink to &quot;Step 2 — Fund (if needed)&quot;">​</a></h2><p>If your MuHaven wallet&#39;s mhUSDC balance is below the checkout amount, the page shows a funding sub-flow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You need 500.00 mhUSDC to complete this purchase.</span></span>
<span class="line"><span>Current balance: 0.00 mhUSDC</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Get test mhUSDC (faucet)]    [Cancel]</span></span></code></pre></div><p>On testnet (Arb Sepolia), the <strong>faucet redirect</strong> opens a new tab to the public testnet faucet. Pick the amount, request, come back to the checkout tab — it polls your balance every 5 seconds and auto-advances when funds land.</p><p>On production (Arb One), the checkout uses an on-ramp picker — pay with card / Apple Pay / Google Pay and the page polls until funds arrive.</p><h2 id="step-3-—-confirm-the-purchase" tabindex="-1">Step 3 — Confirm the purchase <a class="header-anchor" href="#step-3-—-confirm-the-purchase" aria-label="Permalink to &quot;Step 3 — Confirm the purchase&quot;">​</a></h2><p>The page renders the final preview:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Confirm purchase                                    │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  You&#39;re paying        500.00 mhUSDC                  │</span></span>
<span class="line"><span>│  You&#39;ll receive       ~498.50 RWA1 (encrypted)     │</span></span>
<span class="line"><span>│  NAV                  $1.003                         │</span></span>
<span class="line"><span>│  Slippage             0.30% max                      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Signing as           0x1234…cdef                    │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  [Cancel]                              [Pay 500]     │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><p>Tap <strong>Pay 500</strong>. Your passkey signs the UserOp. The SSE channel streams settlement progress:</p><ul><li>&quot;Signed → submitted to bundler…&quot;</li><li>&quot;Settled in tx 0xdef...&quot;</li></ul><p>And the success page renders:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ✅ Paid                                             │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  500.00 mhUSDC → 498.50 RWA1 (encrypted)           │</span></span>
<span class="line"><span>│  Tx: 0xdef... [View on Arbiscan]                     │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Your new RWA1 balance is encrypted on-chain.      │</span></span>
<span class="line"><span>│  To see the cleartext value or claim future yield,   │</span></span>
<span class="line"><span>│  sign in to https://muhaven.app                      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  [Open my dashboard]                                 │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="what-you-just-bought" tabindex="-1">What you just bought <a class="header-anchor" href="#what-you-just-bought" aria-label="Permalink to &quot;What you just bought&quot;">​</a></h2><p>You hold an encrypted balance of an RWA token. Specifically:</p><ul><li>The on-chain <code>MuHavenToken._balances[your_address]</code> is an <code>euint128</code> ciphertext.</li><li>Only you (with your MuHaven wallet + decrypt permit) can unseal it.</li><li>The token issuer can distribute yield to all holders; you&#39;ll claim your share with <code>position.claim</code> when an epoch finalizes.</li></ul><p>To inspect your balance: open <code>muhaven.app</code>, sign in with the passkey you just created, navigate to <strong>Portfolio</strong>.</p><h2 id="privacy-properties" tabindex="-1">Privacy properties <a class="header-anchor" href="#privacy-properties" aria-label="Permalink to &quot;Privacy properties&quot;">​</a></h2><ul><li><strong>The MuHaven operator did not see the cleartext payload.</strong> They have your wallet address (it&#39;s on-chain), the session ID, the issuer label, and the on-chain settlement event. They do <strong>not</strong> have the cleartext amount unless they query the indexer aggregates — which sees only the public ciphertext handle.</li><li><strong>The buyer&#39;s strategy stays private.</strong> Sub-purchases, partial buys, and follow-on actions are individual on-chain transactions; no metadata aggregation by the operator.</li><li><strong>The passkey RP-ID</strong> is hard-pinned to <code>muhaven.app</code>. A phishing link at <code>muhaven-pay.com</code> cannot complete the ceremony.</li></ul><h2 id="what-if-the-link-is-expired-or-cancelled" tabindex="-1">What if the link is expired or cancelled? <a class="header-anchor" href="#what-if-the-link-is-expired-or-cancelled" aria-label="Permalink to &quot;What if the link is expired or cancelled?&quot;">​</a></h2><ul><li><strong>Expired</strong> → page shows &quot;This checkout has expired. Ask the issuer for a fresh link.&quot;</li><li><strong>Cancelled</strong> → page shows &quot;This checkout was cancelled by the issuer.&quot;</li><li><strong>Session not found</strong> → either the path is wrong or the fragment key is missing. Check that your link still has the <code>#k=...</code> part.</li></ul><h2 id="returning-buyer-benefits" tabindex="-1">Returning buyer benefits <a class="header-anchor" href="#returning-buyer-benefits" aria-label="Permalink to &quot;Returning buyer benefits&quot;">​</a></h2><p>Because your MuHaven wallet is the same across MuHaven surfaces, <strong>after one checkout</strong>:</p><ul><li>You can sign in to <code>muhaven.app</code> and see your full portfolio.</li><li>You can use HavenBot to claim yield as epochs finalize.</li><li>You can install <code>@muhaven/mcp</code> to drive the same account from Claude Code / Desktop / Cursor.</li><li>You can link your Telegram with <code>@muhaven_bot</code>.</li></ul><p>One passkey, one MuHaven wallet, every surface.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/checkout/fragment-key">URL fragment key</a> — the privacy mechanic.</li><li><a href="/checkout/for-issuers">For issuers</a> — what the other side looks like.</li><li><a href="/checkout/troubleshooting">Troubleshooting</a> — common buyer-side issues.</li></ul>`,45)])])}const y=a(p,[["render",o]]);export{d as __pageData,y as default};
